def solve(n: Long, edges: Array[Array[Long]], label: String): Long = {
  val adj = Array.fill(n.toInt)(Array[Long]())
  for (edge <- edges) {
    val u = edge(0).toInt
    val v = edge(1).toInt
    adj(u) = adj(u) :+ v
    adj(v) = adj(v) :+ u
  }

  var maxLen = 1

  def dfs(node: Int, visited: Array[Boolean], path: Array[Char]): Unit = {
    val l = path.length
    if (l > 0) {
      var isPalindrome = true
      for (i <- 0 until l / 2) {
        if (path(i) != path(l - 1 - i)) {
          isPalindrome = false
          break
        }
      }
      if (isPalindrome) {
        maxLen = math.max(maxLen, l)
      }
    }

    for (neighbor <- adj(node)) {
      if (!visited(neighbor)) {
        val newVisited = visited.clone()
        newVisited(neighbor) = true
        val newPath = path :+ label(neighbor).toChar
        dfs(neighbor, newVisited, newPath)
      }
    }
  }

  for (i <- 0 until n.toInt) {
    val visited = Array.fill[Boolean](n.toInt)(false)
    visited(i) = true
    val path = Array[Char](label(i).toChar)
    dfs(i, visited, path)
  }

  maxLen
}
